import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Coordinates {
  lat: number;
  lng: number;
}

export interface TransportDetail {
  mode: 'WALK' | 'DRIVE' | 'TRANSIT' | 'TAXI' | 'OTHER';
  duration?: string;
  cost?: string;
  notes?: string;
  routeMapUrl?: string;
}

export interface Activity {
  id: string; // Unique ID for React keys
  name: string;
  description: string;
  startTime?: string;
  endTime?: string;
  locationName: string;
  coordinates?: Coordinates;
  googleMapsUrl: string;
  openingHours?: string;
  transportToNext?: TransportDetail;
}

export interface DayItinerary {
  dayNumber: number;
  date?: string; // YYYY-MM-DD or descriptive
  theme?: string;
  activities: Activity[];
}

export interface TripItinerary {
  title: string;
  summary: string;
  days: DayItinerary[];
}

export enum ViewMode {
  VISUAL = 'VISUAL',
  MARKDOWN = 'MARKDOWN',
  JSON = 'JSON'
}

import { TripItinerary } from '../types';

export const generateMarkdown = (itinerary: TripItinerary): string => {
  let md = `# ${itinerary.title}\n\n`;

  if (itinerary.summary) {
    md += `> ${itinerary.summary}\n\n`;
  }

  itinerary.days.forEach((day) => {
    md += `## Day ${day.dayNumber}${day.date ? ` - ${day.date}` : ''}`;
    if (day.theme) md += `: ${day.theme}`;
    md += `\n\n`;

    day.activities.forEach((activity, index) => {
      const timeStr = activity.startTime ? `**${activity.startTime}${activity.endTime ? ` - ${activity.endTime}` : ''}**` : '';

      md += `### ${index + 1}. [${activity.name}](${activity.googleMapsUrl})\n`;
      if (timeStr) md += `- 🕒 時間: ${timeStr}\n`;
      md += `- 📍 地點: ${activity.locationName}\n`;
      if (activity.openingHours) md += `- ℹ️ 營業時間: ${activity.openingHours}\n`;
      md += `- 📝 說明: ${activity.description}\n`;

      if (activity.transportToNext) {
        const t = activity.transportToNext;
        md += `\n> 🚍 **交通往下一站**: ${t.mode} (${t.duration || 'N/A'})\n`;
        if (t.notes) md += `> *備註: ${t.notes}*\n`;
        if (t.routeMapUrl) md += `> [查看路線](${t.routeMapUrl})\n`;
      }

      md += `\n`;
    });

    md += `---\n\n`;
  });

  return md;
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripItinerary } from "../types";

// Define the schema for the output
const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A catchy title for the trip" },
    summary: { type: Type.STRING, description: "A brief summary of the entire itinerary" },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          dayNumber: { type: Type.INTEGER },
          date: { type: Type.STRING, description: "Date string if available, e.g., 2023-10-27, or Day 1" },
          theme: { type: Type.STRING, description: "Main theme or area of the day" },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING, description: "Unique random ID" },
                name: { type: Type.STRING, description: "Name of the place or activity" },
                description: { type: Type.STRING, description: "Short description of what to do there" },
                startTime: { type: Type.STRING, description: "Start time e.g. 09:00" },
                endTime: { type: Type.STRING, description: "End time e.g. 10:30" },
                locationName: { type: Type.STRING, description: "Full address or searchable location name" },
                coordinates: {
                  type: Type.OBJECT,
                  properties: {
                    lat: { type: Type.NUMBER },
                    lng: { type: Type.NUMBER }
                  },
                  description: "Estimated coordinates of the location"
                },
                googleMapsUrl: { type: Type.STRING, description: "A google maps search link for the location" },
                openingHours: { type: Type.STRING, description: "Opening hours info if mentioned or generally known" },
                transportToNext: {
                  type: Type.OBJECT,
                  description: "Transport details to reach the NEXT activity",
                  properties: {
                    mode: { type: Type.STRING, enum: ['WALK', 'DRIVE', 'TRANSIT', 'TAXI', 'OTHER'] },
                    duration: { type: Type.STRING, description: "Estimated duration text e.g. 15 mins" },
                    notes: { type: Type.STRING, description: "Transport specifics e.g. Take Bus 260" },
                    routeMapUrl: { type: Type.STRING, description: "Google maps directions link to next stop" }
                  }
                }
              },
              required: ["name", "locationName", "googleMapsUrl"]
            }
          }
        },
        required: ["dayNumber", "activities"]
      }
    }
  },
  required: ["title", "days"]
};

export const parseItinerary = async (text: string): Promise<TripItinerary> => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY is not set in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a professional travel planner. 
    Analyze the following unstructured travel itinerary text. 
    Convert it into a structured JSON format suitable for a travel app.

    IMPORTANT:
    1. Infer specific Google Maps Search URLs for each location.
    2. Infer Google Maps Direction URLs for 'transportToNext' based on the current location and the next location in the list.
    3. If coordinates are not explicitly in the text, estimate them based on the location name (general city center or landmark location).
    4. Detect language automatically, but ensure the output fields (descriptions, names) are in Traditional Chinese (zh-TW) unless the input is strictly another language, but prefer Chinese for this user.
    5. Handle relative dates (Day 1, Day 2) if specific dates aren't provided.

    Itinerary Text:
    ${text}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        thinkingConfig: { thinkingBudget: 2048 } // Allow some thinking for complex parsing
      },
    });

    if (!response.text) {
      throw new Error("No response text from Gemini");
    }

    const data = JSON.parse(response.text) as TripItinerary;
    return data;

  } catch (error) {
    console.error("Error parsing itinerary:", error);
    throw error;
  }
};

import React from 'react';
import { TransportDetail } from '../types';

interface TransportCardProps {
  transport: TransportDetail;
}

const TransportCard: React.FC<TransportCardProps> = ({ transport }) => {
  const getIcon = (mode: string) => {
    switch (mode) {
      case 'WALK': return '🚶';
      case 'DRIVE': return '🚗';
      case 'TRANSIT': return '🚌';
      case 'TAXI': return '🚕';
      default: return '🚀';
    }
  };

  return (
    <div className="ml-8 pl-8 border-l-2 border-dashed border-slate-300 py-4 my-2 relative">
      <div className="absolute -left-3 top-1/2 -translate-y-1/2 bg-slate-100 p-1 rounded-full border border-slate-300 text-sm">
        {getIcon(transport.mode)}
      </div>
      <div className="bg-slate-50 p-3 rounded-md text-sm text-slate-600 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2">
        <div className="flex flex-col">
          <span className="font-medium text-slate-700">
            {transport.mode === 'WALK' ? '步行' : 
             transport.mode === 'DRIVE' ? '開車' : 
             transport.mode === 'TRANSIT' ? '大眾運輸' : 
             transport.mode === 'TAXI' ? '計程車' : '交通'}
             {' '}{transport.duration && `• ${transport.duration}`}
          </span>
          {transport.notes && <span className="text-xs text-slate-500 mt-1">{transport.notes}</span>}
        </div>
        {transport.routeMapUrl && (
          <a 
            href={transport.routeMapUrl} 
            target="_blank" 
            rel="noopener noreferrer"
            className="text-blue-600 hover:text-blue-800 text-xs font-semibold hover:underline flex items-center gap-1"
          >
            查看路線 ↗
          </a>
        )}
      </div>
    </div>
  );
};

export default TransportCard;

