import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripItinerary } from "../types";

// Define the schema for the output
const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A catchy title for the trip" },
    summary: { type: Type.STRING, description: "A brief summary of the entire itinerary" },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          dayNumber: { type: Type.INTEGER },
          date: { type: Type.STRING, description: "Date string if available, e.g., 2023-10-27, or Day 1" },
          theme: { type: Type.STRING, description: "Main theme or area of the day" },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING, description: "Unique random ID" },
                name: { type: Type.STRING, description: "Name of the place or activity" },
                description: { type: Type.STRING, description: "Short description of what to do there" },
                startTime: { type: Type.STRING, description: "Start time e.g. 09:00" },
                endTime: { type: Type.STRING, description: "End time e.g. 10:30" },
                locationName: { type: Type.STRING, description: "Full address or searchable location name" },
                coordinates: {
                  type: Type.OBJECT,
                  properties: {
                    lat: { type: Type.NUMBER },
                    lng: { type: Type.NUMBER }
                  },
                  description: "Estimated coordinates of the location"
                },
                googleMapsUrl: { type: Type.STRING, description: "A google maps search link for the location" },
                openingHours: { type: Type.STRING, description: "Opening hours info if mentioned or generally known" },
                transportToNext: {
                  type: Type.OBJECT,
                  description: "Transport details to reach the NEXT activity",
                  properties: {
                    mode: { type: Type.STRING, enum: ['WALK', 'DRIVE', 'TRANSIT', 'TAXI', 'OTHER'] },
                    duration: { type: Type.STRING, description: "Estimated duration text e.g. 15 mins" },
                    notes: { type: Type.STRING, description: "Transport specifics e.g. Take Bus 260" },
                    routeMapUrl: { type: Type.STRING, description: "Google maps directions link to next stop" }
                  }
                },
                suggestedRestaurants: {
                  type: Type.ARRAY,
                  description: "1-2 recommended restaurants nearby if this activity is near Lunch or Dinner time.",
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      cuisine: { type: Type.STRING, description: "e.g. Japanese, Italian, Local Speciality" },
                      description: { type: Type.STRING, description: "Why is it recommended?" },
                      googleMapsUrl: { type: Type.STRING },
                      websiteUrl: { type: Type.STRING, description: "Official website or booking link" }
                    },
                    required: ["name", "googleMapsUrl"]
                  }
                }
              },
              required: ["name", "locationName", "googleMapsUrl"]
            }
          }
        },
        required: ["dayNumber", "activities"]
      }
    }
  },
  required: ["title", "days"]
};

export const parseItinerary = async (text: string): Promise<TripItinerary> => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY is not set in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a professional travel planner. 
    Analyze the following unstructured travel itinerary text. 
    Convert it into a structured JSON format suitable for a travel app.

    IMPORTANT INSTRUCTIONS:
    1. Infer specific Google Maps Search URLs for each location.
    2. Infer Google Maps Direction URLs for 'transportToNext' based on the current location and the next location.
    3. If coordinates are not explicitly in the text, estimate them based on the location name.
    4. **Restaurant Suggestions**: For activities that occur around typical meal times (Lunch ~12:00, Dinner ~18:00), OR if there is a long gap suitable for eating, please suggest 1-2 highly-rated restaurants nearby the current location.
       - Focus on local specialties or distinct cuisines fitting the area.
       - Provide the restaurant name, cuisine type, description, Google Maps link, and an official website/booking link if found.
       - Add these to the 'suggestedRestaurants' field of the relevant activity.
    5. Detect language automatically, but ensure the output fields (descriptions, names, restaurant info) are in Traditional Chinese (zh-TW).

    Itinerary Text:
    ${text}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        thinkingConfig: { thinkingBudget: 2048 } // Allow some thinking for complex parsing and searching
      },
    });

    if (!response.text) {
      throw new Error("No response text from Gemini");
    }

    const data = JSON.parse(response.text) as TripItinerary;
    return data;

  } catch (error) {
    console.error("Error parsing itinerary:", error);
    throw error;
  }
};

