import { TripItinerary } from '../types';

export const generateMarkdown = (itinerary: TripItinerary): string => {
  let md = `# ${itinerary.title}\n\n`;

  if (itinerary.summary) {
    md += `> ${itinerary.summary}\n\n`;
  }

  itinerary.days.forEach((day) => {
    md += `## Day ${day.dayNumber}${day.date ? ` - ${day.date}` : ''}`;
    if (day.theme) md += `: ${day.theme}`;
    md += `\n\n`;

    day.activities.forEach((activity, index) => {
      const timeStr = activity.startTime ? `**${activity.startTime}${activity.endTime ? ` - ${activity.endTime}` : ''}**` : '';

      md += `### ${index + 1}. [${activity.name}](${activity.googleMapsUrl})\n`;
      if (timeStr) md += `- 🕒 時間: ${timeStr}\n`;
      md += `- 📍 地點: ${activity.locationName}\n`;
      if (activity.openingHours) md += `- ℹ️ 營業時間: ${activity.openingHours}\n`;
      md += `- 📝 說明: ${activity.description}\n`;

      if (activity.suggestedRestaurants && activity.suggestedRestaurants.length > 0) {
        md += `\n**🍽️ 推薦美食**:\n`;
        activity.suggestedRestaurants.forEach(r => {
          md += `- **[${r.name}](${r.googleMapsUrl})** (${r.cuisine})`;
          if (r.websiteUrl) md += ` [🔗 官網](${r.websiteUrl})`;
          md += `\n  - ${r.description}\n`;
        });
      }

      if (activity.transportToNext) {
        const t = activity.transportToNext;
        md += `\n> 🚍 **交通往下一站**: ${t.mode} (${t.duration || 'N/A'})\n`;
        if (t.notes) md += `> *備註: ${t.notes}*\n`;
        if (t.routeMapUrl) md += `> [查看路線](${t.routeMapUrl})\n`;
      }

      md += `\n`;
    });

    md += `---\n\n`;
  });

  return md;
};

import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

export const exportToPDF = async (elementId: string, fileName: string) => {
  const element = document.getElementById(elementId);
  if (!element) {
    console.error(`Element with id ${elementId} not found`);
    return;
  }

  // Add a class to handle specific styling overrides for PDF (like removing sticky headers)
  element.classList.add('pdf-export-mode');

  try {
    // Wait a brief moment for styles to apply (though usually synchronous, good for safety)
    await new Promise(resolve => setTimeout(resolve, 100));

    const canvas = await html2canvas(element, {
      scale: 2, // Higher scale for better quality
      useCORS: true, // Allow cross-origin images if any
      logging: false,
      backgroundColor: '#ffffff',
      windowWidth: 1024, // Fix window width to ensure consistent layout
    });

    const imgData = canvas.toDataURL('image/png');

    // A4 dimensions in mm
    const pdfWidth = 210;
    const pdfHeight = 297;

    const pdf = new jsPDF('p', 'mm', 'a4');

    const imgProps = pdf.getImageProperties(imgData);
    const pdfImgWidth = pdfWidth;
    const pdfImgHeight = (imgProps.height * pdfImgWidth) / imgProps.width;

    // Handle pagination if content is longer than one page
    let heightLeft = pdfImgHeight;
    let position = 0;

    // First page
    pdf.addImage(imgData, 'PNG', 0, position, pdfImgWidth, pdfImgHeight);
    heightLeft -= pdfHeight;

    // Subsequent pages
    while (heightLeft > 0) {
      position = heightLeft - pdfImgHeight; // This logic effectively aligns the next slice
      // However, addImage with negative position simply draws the image shifted up.
      // Correct logic for multipage slicing:
      pdf.addPage();
      // We calculate the new position to start drawing the image 'higher' up (off canvas)
      // The position needs to be: - (totalHeight - heightLeft) essentially
      // But simpler: each page shifts the image up by pdfHeight.
      // 2nd page: position = -297
      // 3rd page: position = -594

      const pageIndex = Math.ceil((pdfImgHeight - heightLeft) / pdfHeight);
      const newPos = -(pdfHeight * pageIndex);

      pdf.addImage(imgData, 'PNG', 0, newPos, pdfImgWidth, pdfImgHeight);
      heightLeft -= pdfHeight;
    }

    pdf.save(`${fileName}.pdf`);
  } catch (err) {
    console.error('PDF Generation failed', err);
    throw err;
  } finally {
    element.classList.remove('pdf-export-mode');
  }
};

