import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripItinerary } from "../types";

// Define the schema for the output
const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A catchy title for the trip" },
    summary: { type: Type.STRING, description: "A brief summary of the entire itinerary" },
    pace: { type: Type.STRING, description: "Overall pace: e.g. 'Relaxed', 'Packed', 'Standard'" },
    transportStrategy: { type: Type.STRING, description: "Main transport mode overview, e.g. 'Public Transit + JR Pass' or 'Self-drive'" },
    routeConcept: { type: Type.STRING, description: "Brief description of the geographical flow" },
    budgetEstimate: {
      type: Type.OBJECT,
      properties: {
        total: { type: Type.STRING, description: "Total estimated cost string" },
        breakdown: {
          type: Type.OBJECT,
          properties: {
            transport: { type: Type.STRING },
            dining: { type: Type.STRING },
            tickets: { type: Type.STRING },
            other: { type: Type.STRING }
          }
        }
      }
    },
    riskManagement: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of general risks: typhoons, holidays, strikes, etc."
    },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          dayNumber: { type: Type.INTEGER },
          date: { type: Type.STRING },
          theme: { type: Type.STRING },
          dailyBudgetEstimate: { type: Type.STRING, description: "Rough estimate for the day" },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                startTime: { type: Type.STRING },
                endTime: { type: Type.STRING },
                duration: { type: Type.STRING, description: "Suggested stay duration e.g. '2 hours'" },
                locationName: { type: Type.STRING },
                coordinates: {
                  type: Type.OBJECT,
                  properties: {
                    lat: { type: Type.NUMBER },
                    lng: { type: Type.NUMBER }
                  }
                },
                googleMapsUrl: { type: Type.STRING },
                openingHours: { type: Type.STRING },
                estimatedCost: { type: Type.STRING, description: "Cost for ticket/entry e.g. '2000 JPY'" },
                bookingNotes: { type: Type.STRING, description: "Reservation requirements or 'Walk-in'" },
                fallbackPlan: { type: Type.STRING, description: "Alternative if closed or bad weather" },
                accessibilityNotes: { type: Type.STRING, description: "Wheelchair/stroller access notes" },
                transportToNext: {
                  type: Type.OBJECT,
                  properties: {
                    mode: { type: Type.STRING, enum: ['WALK', 'DRIVE', 'TRANSIT', 'TAXI', 'OTHER'] },
                    duration: { type: Type.STRING },
                    distance: { type: Type.STRING, description: "e.g. 500m or 10km" },
                    notes: { type: Type.STRING },
                    routeMapUrl: { type: Type.STRING }
                  }
                },
                suggestedRestaurants: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      cuisine: { type: Type.STRING },
                      description: { type: Type.STRING },
                      googleMapsUrl: { type: Type.STRING },
                      websiteUrl: { type: Type.STRING }
                    },
                    required: ["name", "googleMapsUrl"]
                  }
                }
              },
              required: ["name", "locationName", "googleMapsUrl"]
            }
          }
        },
        required: ["dayNumber", "activities"]
      }
    }
  },
  required: ["title", "days"]
};

export const parseItinerary = async (text: string): Promise<TripItinerary> => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY is not set in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a detailed Travel Planner AI. 
    Analyze the unstructured travel text and convert it into a HIGHLY STRUCTURED JSON itinerary.

    **Requirements for Extraction:**
    1. **Logistics**: Infer Google Maps Search URLs and Direction URLs. Estimate Lat/Lng.
    2. **Transport**: For 'transportToNext', estimate realistic duration and distance.
    3. **Planning Meta-data**: 
       - Infer the overall 'pace' (Relaxed/Intense).
       - Infer 'transportStrategy' (e.g., using day passes, rental car).
       - Estimate a 'budgetEstimate' breakdown based on the location's typical costs (if not specified).
    4. **Activity Details**:
       - 'estimatedCost': Estimate entry fees/spending.
       - 'bookingNotes': Flag if reservations are usually needed (e.g., popular museums, fancy dining).
       - 'fallbackPlan': Suggest an indoor alternative if the main activity is outdoors (for rain) or a nearby alternative.
       - 'accessibilityNotes': Note if a place is known to be hilly or walk-heavy.
    5. **Restaurants**: Suggest 1-2 nearby restaurants for lunch/dinner slots if none are provided.

    **Language**: 
    - Output primarily in Traditional Chinese (zh-TW).

    Itinerary Text:
    ${text}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        thinkingConfig: { thinkingBudget: 4096 } // Increased budget for detailed analysis
      },
    });

    if (!response.text) {
      throw new Error("No response text from Gemini");
    }

    const data = JSON.parse(response.text) as TripItinerary;
    return data;

  } catch (error) {
    console.error("Error parsing itinerary:", error);
    throw error;
  }
};

import { TripItinerary } from '../types';

export const generateMarkdown = (itinerary: TripItinerary): string => {
  let md = `# ${itinerary.title}\n\n`;

  // Section 1: Itinerary Overview
  md += `## 1. 行程總覽 (Overview)\n\n`;
  if (itinerary.summary) md += `> **摘要**: ${itinerary.summary}\n\n`;

  md += `- **📅 旅程天數**: ${itinerary.days.length} 天\n`;
  if (itinerary.pace) md += `- **⚡ 節奏**: ${itinerary.pace}\n`;
  if (itinerary.transportStrategy) md += `- **🚆 交通策略**: ${itinerary.transportStrategy}\n`;
  if (itinerary.routeConcept) md += `- **📍 主要動線**: ${itinerary.routeConcept}\n`;

  if (itinerary.budgetEstimate) {
    const b = itinerary.budgetEstimate;
    md += `- **💰 總預算概算**: ${b.total}\n`;
    if (b.breakdown) {
      md += `  - 交通: ${b.breakdown.transport || 'N/A'}\n`;
      md += `  - 餐飲: ${b.breakdown.dining || 'N/A'}\n`;
      md += `  - 門票: ${b.breakdown.tickets || 'N/A'}\n`;
      md += `  - 其他: ${b.breakdown.other || 'N/A'}\n`;
    }
  }
  md += `\n---\n\n`;

  // Section 2: Daily Itinerary
  md += `## 2. 每日行程細節 (Daily Itinerary)\n\n`;

  itinerary.days.forEach((day) => {
    md += `### 🗓️ Day ${day.dayNumber}${day.date ? ` (${day.date})` : ''}: ${day.theme || ''}\n`;
    if (day.dailyBudgetEstimate) md += `> 💵 本日預算估計: ${day.dailyBudgetEstimate}\n\n`;

    day.activities.forEach((activity, index) => {
      const title = activity.name;
      const coords = activity.coordinates ? `(${activity.coordinates.lat.toFixed(4)}, ${activity.coordinates.lng.toFixed(4)})` : '';

      md += `#### ${index + 1}. [${title}](${activity.googleMapsUrl}) ${coords}\n`;

      // Basic Info
      md += `- **📝 簡介**: ${activity.description}\n`;

      const timeInfo = [];
      if (activity.startTime) timeInfo.push(`${activity.startTime}${activity.endTime ? ` - ${activity.endTime}` : ''}`);
      if (activity.duration) timeInfo.push(`停留約 ${activity.duration}`);
      if (timeInfo.length) md += `- **⏰ 時間**: ${timeInfo.join(' | ')}\n`;

      if (activity.openingHours) md += `- **ℹ️ 開放時間**: ${activity.openingHours}\n`;
      if (activity.estimatedCost) md += `- **💲 預估費用**: ${activity.estimatedCost}\n`;
      if (activity.bookingNotes) md += `- **🎫 訂位/購票**: ${activity.bookingNotes}\n`;
      if (activity.accessibilityNotes) md += `- **♿ 無障礙/友善提示**: ${activity.accessibilityNotes}\n`;
      if (activity.fallbackPlan) md += `- **☔ 雨天/備案**: ${activity.fallbackPlan}\n`;

      // Transport to next
      if (activity.transportToNext) {
        const t = activity.transportToNext;
        md += `\n> **⬇️ 前往下一站**: [查看路線](${t.routeMapUrl || '#'}) \n`;
        md += `> - 方式: ${t.mode}\n`;
        if (t.duration) md += `> - 時間: ${t.duration}\n`;
        if (t.distance) md += `> - 距離: ${t.distance}\n`;
        if (t.notes) md += `> - 備註: ${t.notes}\n`;
      }

      // Restaurants
      if (activity.suggestedRestaurants && activity.suggestedRestaurants.length > 0) {
        md += `\n**🍽️ 附近推薦用餐**:\n`;
        activity.suggestedRestaurants.forEach(r => {
          md += `- [${r.name}](${r.googleMapsUrl}) (${r.cuisine}): ${r.description}`;
          if (r.websiteUrl) md += ` [預約連結](${r.websiteUrl})`;
          md += `\n`;
        });
      }
      md += `\n`;
    });
    md += `\n`;
  });

  md += `---\n\n`;

  // Section 3: Reservations & Tickets Summary
  md += `## 3. ⚠️ 訂位與票券檢查清單 (Reservations)\n\n`;
  let hasReservations = false;
  itinerary.days.forEach(day => {
    day.activities.forEach(act => {
      if (act.bookingNotes && !act.bookingNotes.includes('無') && !act.bookingNotes.includes('None')) {
        hasReservations = true;
        md += `- **Day ${day.dayNumber} - ${act.name}**: ${act.bookingNotes}\n`;
      }
    });
  });
  if (!hasReservations) md += `*本行程似乎無需特別提前預訂，但建議熱門餐廳仍可先行確認。*\n`;
  md += `\n---\n\n`;

  // Section 4: Cost & Risk Management
  md += `## 4. 📊 成本與風險控管 (Costs & Risks)\n\n`;

  if (itinerary.riskManagement && itinerary.riskManagement.length > 0) {
    md += `### 風險清單\n`;
    itinerary.riskManagement.forEach(risk => md += `- ⚠️ ${risk}\n`);
    md += `\n`;
  } else {
    md += `### 風險提示\n- 建議出發前再次確認天氣與交通營運狀況。\n\n`;
  }

  md += `### 預算總結\n`;
  if (itinerary.budgetEstimate?.total) {
    md += `- **預估總花費**: ${itinerary.budgetEstimate.total}\n`;
    md += `- *此為概算，實際費用視匯率與個人消費習慣而定。*\n`;
  } else {
    md += `- 未提供詳細預算資訊。\n`;
  }

  return md;
};

