import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TripItinerary } from "../types";

// Define the schema for the output
const itinerarySchema: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A catchy title for the trip" },
    summary: { type: Type.STRING, description: "A brief summary of the entire itinerary" },
    pace: { type: Type.STRING, description: "Overall pace: e.g. 'Relaxed', 'Packed', 'Standard'" },
    transportStrategy: { type: Type.STRING, description: "Main transport mode overview, e.g. 'Public Transit + JR Pass' or 'Self-drive'" },
    routeConcept: { type: Type.STRING, description: "Brief description of the geographical flow" },
    budgetEstimate: {
      type: Type.OBJECT,
      properties: {
        total: { type: Type.STRING, description: "Total estimated cost string" },
        breakdown: {
          type: Type.OBJECT,
          properties: {
            transport: { type: Type.STRING },
            dining: { type: Type.STRING },
            tickets: { type: Type.STRING },
            other: { type: Type.STRING }
          }
        }
      }
    },
    riskManagement: {
      type: Type.ARRAY,
      items: { type: Type.STRING },
      description: "List of general risks: typhoons, holidays, strikes, etc."
    },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          dayNumber: { type: Type.INTEGER },
          date: { type: Type.STRING },
          theme: { type: Type.STRING },
          dailyBudgetEstimate: { type: Type.STRING, description: "Rough estimate for the day" },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                startTime: { type: Type.STRING },
                endTime: { type: Type.STRING },
                duration: { type: Type.STRING, description: "Suggested stay duration e.g. '2 hours'" },
                locationName: { type: Type.STRING },
                coordinates: {
                  type: Type.OBJECT,
                  properties: {
                    lat: { type: Type.NUMBER },
                    lng: { type: Type.NUMBER }
                  }
                },
                googleMapsUrl: { type: Type.STRING },
                openingHours: { type: Type.STRING },
                estimatedCost: { type: Type.STRING, description: "Cost for ticket/entry e.g. '2000 JPY'" },
                bookingNotes: { type: Type.STRING, description: "Reservation requirements or 'Walk-in'" },
                fallbackPlan: { type: Type.STRING, description: "Alternative if closed or bad weather" },
                accessibilityNotes: { type: Type.STRING, description: "Wheelchair/stroller access notes" },
                transportToNext: {
                  type: Type.OBJECT,
                  properties: {
                    mode: { type: Type.STRING, enum: ['WALK', 'DRIVE', 'TRANSIT', 'TAXI', 'OTHER'] },
                    duration: { type: Type.STRING },
                    distance: { type: Type.STRING, description: "e.g. 500m or 10km" },
                    notes: { type: Type.STRING },
                    routeMapUrl: { type: Type.STRING }
                  }
                },
                suggestedRestaurants: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      cuisine: { type: Type.STRING },
                      description: { type: Type.STRING },
                      googleMapsUrl: { type: Type.STRING },
                      websiteUrl: { type: Type.STRING }
                    },
                    required: ["name", "googleMapsUrl"]
                  }
                }
              },
              required: ["name", "locationName", "googleMapsUrl"]
            }
          }
        },
        required: ["dayNumber", "activities"]
      }
    }
  },
  required: ["title", "days"]
};

export const parseItinerary = async (text: string): Promise<TripItinerary> => {
  if (!process.env.API_KEY) {
    throw new Error("API_KEY is not set in environment variables.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are a detailed Travel Planner AI. 
    Analyze the unstructured travel text and convert it into a HIGHLY STRUCTURED JSON itinerary.

    **Requirements for Extraction & Map Links (CRITICAL):**
    1. **Google Maps URLs**:
       - **Activities**: Generate a functional Google Maps Search URL for EVERY location.
         Format: \`https://www.google.com/maps/search/?api=1&query={Specific+Place_Name}+{City/Region}\`
         *IMPORTANT*: ALWAYS append the city or region to the query to disambiguate (e.g., "Grand Hotel" exists in many cities).
         If the destination is in a non-English speaking country, prefer the **Native/Local Name** + **City** (e.g. "清水寺 Kyoto" instead of "Pure Water Temple").
       - **Routes (transportToNext)**: Generate a functional Google Maps Directions URL between activities.
         Format: \`https://www.google.com/maps/dir/?api=1&origin={Origin_Name}+{City}&destination={Destination_Name}+{City}&travelmode={driving|transit|walking}\`
         (Ensure origin/destination names include city context to avoid routing errors).
    2. **Transport Data**: 
       - Estimate realistic **duration** (e.g., "25 mins") and **distance** (e.g., "3.2 km") for movement between places.
    3. **Logistics**: Estimate Lat/Lng for visualization if possible.
    4. **Planning Meta-data**: 
       - Infer 'pace', 'transportStrategy', and 'budgetEstimate'.
    5. **Activity Details**:
       - 'estimatedCost', 'bookingNotes', 'fallbackPlan', 'accessibilityNotes'.
    6. **Restaurants**: 
       - Suggest 1-2 nearby restaurants if none provided.
       - Ensure restaurant Map URLs also use the \`{Restaurant_Name}+{City}\` format for accuracy.

    **Language**: 
    - Output primarily in Traditional Chinese (zh-TW).
    - Map Query Parameters (origin, destination, query) should use the most accurate searchable name (English or Local).

    Itinerary Text:
    ${text}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
        thinkingConfig: { thinkingBudget: 4096 }
      },
    });

    if (!response.text) {
      throw new Error("No response text from Gemini");
    }

    const data = JSON.parse(response.text) as TripItinerary;
    return data;

  } catch (error) {
    console.error("Error parsing itinerary:", error);
    throw error;
  }
};

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { TripItinerary } from '../types';

interface TripMapProps {
  itinerary: TripItinerary;
}

const DAY_COLORS = [
  '#2563eb', // Blue (Day 1)
  '#16a34a', // Green (Day 2)
  '#dc2626', // Red (Day 3)
  '#d97706', // Amber (Day 4)
  '#9333ea', // Purple (Day 5)
  '#0891b2', // Cyan
  '#db2777', // Pink
];

const TripMap: React.FC<TripMapProps> = ({ itinerary }) => {
  const mapRef = useRef<HTMLDivElement>(null);
  const mapInstanceRef = useRef<L.Map | null>(null);

  useEffect(() => {
    if (!mapRef.current) return;

    // Initialize map if not already done
    if (!mapInstanceRef.current) {
      mapInstanceRef.current = L.map(mapRef.current).setView([0, 0], 2);

      // Use OpenStreetMap tiles (free, no API key required)
      L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
        attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
        subdomains: 'abcd',
        maxZoom: 19
      }).addTo(mapInstanceRef.current);
    }

    const map = mapInstanceRef.current;

    // Clear existing layers
    map.eachLayer((layer) => {
      if (layer instanceof L.Marker || layer instanceof L.Polyline || layer instanceof L.CircleMarker) {
        map.removeLayer(layer);
      }
    });

    const allPoints: L.LatLngExpression[] = [];
    const bounds = L.latLngBounds([]);

    // Iterate through days to plot markers and lines
    itinerary.days.forEach((day, dayIdx) => {
      const dayColor = DAY_COLORS[dayIdx % DAY_COLORS.length];
      const dayPoints: L.LatLngExpression[] = [];

      day.activities.forEach((activity, actIdx) => {
        if (activity.coordinates && activity.coordinates.lat && activity.coordinates.lng) {
          const { lat, lng } = activity.coordinates;
          const latLng: L.LatLngExpression = [lat, lng];

          dayPoints.push(latLng);
          allPoints.push(latLng);
          bounds.extend(latLng);

          // Create a custom marker (using CircleMarker for cleaner look without assets)
          const marker = L.circleMarker(latLng, {
            radius: 8,
            fillColor: dayColor,
            color: '#fff',
            weight: 2,
            opacity: 1,
            fillOpacity: 0.9
          }).addTo(map);

          // Popup content
          const popupContent = `
            <div class="font-sans min-w-[150px]">
              <div class="text-xs font-bold text-slate-500 mb-1">Day ${day.dayNumber} - #${actIdx + 1}</div>
              <h3 class="font-bold text-sm text-slate-800 mb-1">${activity.name}</h3>
              <p class="text-xs text-slate-600">${activity.locationName || ''}</p>
            </div>
          `;

          marker.bindPopup(popupContent);
        }
      });

      // Draw lines connecting activities for this day
      if (dayPoints.length > 1) {
        L.polyline(dayPoints, {
          color: dayColor,
          weight: 3,
          opacity: 0.7,
          dashArray: '5, 5' // Dashed line to indicate travel
        }).addTo(map);
      }
    });

    // Fit bounds if we have points
    if (allPoints.length > 0) {
      map.fitBounds(bounds, { padding: [50, 50] });
    } else {
        // Fallback view if no coordinates found
        map.setView([20, 0], 2);
    }

    // Cleanup on unmount (optional, but good practice if component is destroyed)
    return () => {
        // We generally keep the map instance if re-renders happen frequently, 
        // but fully destroying it is safer if the component is unmounted.
        // For this specific React setup, we'll let the ref persist until unmount.
    };
  }, [itinerary]);

  return (
    <div className="w-full h-[400px] rounded-xl overflow-hidden border border-slate-200 shadow-sm z-0 relative">
       <div ref={mapRef} className="w-full h-full bg-slate-100" />
       {/* Legend overlay */}
       <div className="absolute bottom-4 right-4 bg-white/90 backdrop-blur p-3 rounded-lg shadow-md text-xs z-[1000] border border-slate-100 max-w-[150px]">
          <h4 className="font-bold mb-2 text-slate-700">每日路線</h4>
          <div className="space-y-1.5 max-h-[100px] overflow-y-auto custom-scrollbar">
            {itinerary.days.map((day, idx) => (
                <div key={idx} className="flex items-center gap-2">
                    <span 
                      className="w-3 h-3 rounded-full flex-shrink-0" 
                      style={{ backgroundColor: DAY_COLORS[idx % DAY_COLORS.length] }}
                    ></span>
                    <span className="truncate text-slate-600">Day {day.dayNumber}</span>
                </div>
            ))}
          </div>
       </div>
    </div>
  );
};

export default TripMap;

import React, { useState, useRef, useEffect } from 'react';
import { TripItinerary } from '../types';
import ActivityCard from './ActivityCard';
import TransportCard from './TransportCard';
import TripMap from './TripMap';

interface VisualItineraryProps {
  data: TripItinerary;
}

const VisualItinerary: React.FC<VisualItineraryProps> = ({ data }) => {
  const [activeDayIndex, setActiveDayIndex] = useState(0);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const activeDay = data.days[activeDayIndex];

  // Auto-scroll the active tab into view when activeDayIndex changes
  useEffect(() => {
    if (scrollContainerRef.current) {
      const container = scrollContainerRef.current;
      const activeTab = container.children[activeDayIndex] as HTMLElement;

      if (activeTab) {
        // Calculate the scroll position to center the active tab
        // We use scrollTo instead of scrollIntoView to prevent the whole page from potentially shifting vertically
        const containerWidth = container.clientWidth;
        const tabWidth = activeTab.offsetWidth;
        const tabLeft = activeTab.offsetLeft;

        const targetScrollLeft = tabLeft - (containerWidth / 2) + (tabWidth / 2);

        container.scrollTo({
          left: targetScrollLeft,
          behavior: 'smooth'
        });
      }
    }
  }, [activeDayIndex]);

  return (
    <div className="space-y-8" id="visual-itinerary">
      {/* Trip Header & Overview */}
      <div className="text-center pt-4">
        <h2 className="text-3xl font-bold text-slate-800 mb-4">{data.title}</h2>
        <p className="text-slate-600 max-w-2xl mx-auto text-lg leading-relaxed mb-8">{data.summary}</p>

        {/* Overview Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 text-left max-w-4xl mx-auto bg-slate-50 p-6 rounded-2xl border border-slate-100 mb-8">

          {/* Pace & Strategy */}
          <div className="space-y-3">
            <div>
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider">旅行節奏</h4>
              <p className="font-medium text-slate-700">{data.pace || '標準'}</p>
            </div>
            <div>
              <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider">交通策略</h4>
              <p className="font-medium text-slate-700">{data.transportStrategy || '混合大眾運輸'}</p>
            </div>
          </div>

          {/* Budget */}
          <div className="lg:col-span-2 bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
            <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">預算概算</h4>
            <div className="flex items-baseline gap-2 mb-2">
              <span className="text-2xl font-bold text-emerald-600">{data.budgetEstimate?.total || '未估算'}</span>
              <span className="text-xs text-slate-500">總計</span>
            </div>
            {data.budgetEstimate?.breakdown && (
              <div className="grid grid-cols-2 gap-x-4 gap-y-1 text-xs text-slate-600">
                <div className="flex justify-between"><span>交通:</span> <span>{data.budgetEstimate.breakdown.transport}</span></div>
                <div className="flex justify-between"><span>餐飲:</span> <span>{data.budgetEstimate.breakdown.dining}</span></div>
                <div className="flex justify-between"><span>門票:</span> <span>{data.budgetEstimate.breakdown.tickets}</span></div>
                <div className="flex justify-between"><span>其他:</span> <span>{data.budgetEstimate.breakdown.other}</span></div>
              </div>
            )}
          </div>

          {/* Risks */}
          <div className="bg-red-50 p-4 rounded-xl border border-red-100">
            <h4 className="text-xs font-bold text-red-400 uppercase tracking-wider mb-2">風險與注意</h4>
            {data.riskManagement && data.riskManagement.length > 0 ? (
              <ul className="text-xs text-red-700 space-y-1 list-disc list-inside">
                {data.riskManagement.map((risk, idx) => (
                  <li key={idx}>{risk}</li>
                ))}
              </ul>
            ) : (
              <p className="text-xs text-red-600">請注意天氣與交通狀況。</p>
            )}
          </div>
        </div>

        {/* Map Visualization */}
        <div className="max-w-4xl mx-auto mb-8 animate-fade-in">
           <TripMap itinerary={data} />
        </div>
      </div>

      {/* Day Navigation Tabs */}
      <div className="sticky top-0 z-30 bg-white pt-2 pb-4 border-b border-slate-100 shadow-sm">
        <div 
          ref={scrollContainerRef}
          className="flex overflow-x-auto gap-3 px-4 pb-2 w-full snap-x scroll-smooth relative"
          style={{ scrollbarWidth: 'thin' }}
        >
          {data.days.map((day, idx) => (
            <button
              key={day.dayNumber}
              onClick={() => setActiveDayIndex(idx)}
